            Email Address <span className="text-danger">*</span>
          </label>
          <input
            type="email"
            className="form-control"
            id="email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
            required
            disabled={isEditing}
            placeholder="user@example.com"
          />
          <small className="form-text text-muted">
            User's email address for the mapping
          </small>
        </div>

        <div className="mb-3">
          <label htmlFor="ipAddress" className="form-label">
            IP Address / Range
          </label>
          <input
            type="text"
            className="form-control"
            id="ipAddress"
            value={ipAddress}
            onChange={(e) => setIpAddress(e.target.value)}
            placeholder="192.168.1.100 or 10.0.0.0/24 or 172.16.0.1-172.16.0.100"
          />
          <small className="form-text text-muted">
            Single IP (192.168.1.100), CIDR (10.0.0.0/24), or dash range (172.16.0.1-172.16.0.100)
          </small>
        </div>

        <div className="mb-3">
          <label htmlFor="awsAccountId" className="form-label">
            AWS Account ID
          </label>
          <input
            type="text"
            className="form-control"
            id="awsAccountId"
            value={awsAccountId}
            onChange={(e) => setAwsAccountId(e.target.value)}
            placeholder="123456789012"
            maxLength={12}
          />
          <small className="form-text text-muted">
            12-digit AWS account ID (optional if IP address provided)
          </small>
        </div>

        <div className="mb-3">
          <label htmlFor="domain" className="form-label">
            Domain
          </label>
          <input
            type="text"
            className="form-control"
            id="domain"
            value={domain}
            onChange={(e) => setDomain(e.target.value)}
            placeholder="example.com"
          />
          <small className="form-text text-muted">
            Organizational domain (optional)
          </small>
        </div>
      </div>

      <div className="card-footer">
        <button
          type="submit"
          className="btn btn-primary"
          disabled={isSubmitting}
        >
          {isSubmitting ? (
            <>
              <span className="spinner-border spinner-border-sm me-2" role="status" aria-hidden="true"></span>
              Saving...
            </>
          ) : (
            isEditing ? 'Update Mapping' : 'Create Mapping'
          )}
        </button>
        <button
          type="button"
          className="btn btn-secondary ms-2"
          onClick={onCancel}
          disabled={isSubmitting}
        >
          Cancel
        </button>
      </div>
    </form>
  );
}

