                                <i className="bi bi-chevron-double-left"></i>
                            </button>
                        </li>
                        <li className={`page-item ${safePage <= 1 ? 'disabled' : ''}`}>
                            <button className="page-link" onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={safePage <= 1}>
