                                            {AVAILABLE_ROLES.map(role => (
                                                <div className="form-check form-check-inline" key={role}>
                                                    <input
                                                        className="form-check-input"
                                                        type="checkbox"
                                                        id={`edit-role-${role}`}
                                                        value={role}
                                                        checked={editUser.roles.includes(role)}
                                                        onChange={handleEditUserRolesChange}
                                                        disabled={isSubmittingEdit}
