                                                    <div className="form-check" key={workgroup.id}>
                                                        <input
                                                            className="form-check-input"
                                                            type="checkbox"
                                                            id={`edit-workgroup-${workgroup.id}`}
                                                            value={workgroup.id}
                                                            checked={editUser.workgroupIds.includes(workgroup.id)}
